import { DatePipe, formatNumber } from "@angular/common";
import { HttpClient, HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { SuspendedDocuments } from "../../Models/Loan/SuspendedDocuments";
import { IBranch } from "../../Models/References/Branch";
import { TranslateService } from "@ngx-translate/core";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { UnSuspendedApplicationRequest } from "../../Models/Loan/UnSuspendApplication";

@Component({
  selector: "app-suspended-documents",
  templateUrl: "./suspended-documents.page.html",
  styleUrls: ["./suspended-documents.page.scss"],
})
export class SuspendedDocumentsPage implements OnInit {
  showLoader: boolean = false;
  details: boolean = false;

  sortingIconClass: string;
  sortingIconParam: string;

  page = 1; // the page we are viewing

  suspendedDocuments: SuspendedDocuments[];
  FilteredDocuments: SuspendedDocuments[];
  curDocument: SuspendedDocuments;

  branches: IBranch[] = [];

  SearchForm: FormGroup = this.formBuilder.group({
    client_name: [""],
    branch_code: [""],
    nation_id: [""],
  });

  constructor(
    private env: EnvService,
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private sortingService: sortingService,
    private alertService: AlertService,
    private loanApplicationsService: LoanApplicationsService,
    public pagingService: pagingService,
    public translate: TranslateService
  ) {}

  ngOnInit() {
    this.GetSuspendedDocuments();
  }

  NumberFormatStyle = (number: string) =>
    formatNumber(Number(number), "en-US", "1.0");

  GetSuspendedDocuments() {
    this.showLoader = true;
    this.http
      .get<SuspendedDocuments[]>(
        this.env.API_URL + `api/LoanApplications/GetSuspendedDocuments`
      )
      .subscribe({
        next: (data) => {
          this.suspendedDocuments = data["entities"];
          this.branches = data["branches"];
          this.FilteredDocuments = this.suspendedDocuments;
          this.showLoader = false;
        },
        error: (error) => {
          this.alertService.showAlertError(error.error, false);
          this.showLoader = false;
        },
      });
  }

  async UnSuspendDocument(document: SuspendedDocuments) {
    if (
      !(await this.alertService.SaveAlert(
        "هل أنت متأكد أنك تريد إلغاء تعليق هذا الطلب؟"
      ))
    )
      return;

    try {
      this.showLoader = true;

      const request: UnSuspendedApplicationRequest = {
        id: document.id,
        org_code: document.org_code,
        branch_code: document.branch_code,
        client_key: document.client_key,
      };

      const result = await this.loanApplicationsService
        .unSuspendApplication(request)
        .toPromise();

      if (result.applicationCode === "-1")
        return this.alertService.showAlertConfirm(
          this.translate.instant(`loans.workflowErrorMessage`),
          true
        );

      const successMessage =
        this.translate.instant(`loanApp.createSuccess`) +
        `: ${result.applicationCode} `;

      this.alertService.showAlertConfirm(successMessage, true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  async DeleteSuspendedDocument(document: SuspendedDocuments) {
    if (!(await this.alertService.SaveAlert())) return;
    try {
      this.showLoader = true;
      await this.loanApplicationsService
        .deleteSuspendedApplication(document)
        .toPromise();
      this.alertService.showAlertConfirm("تم الحذف بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  searchForUsers() {
    this.page = 1;
    let client_name = this.SearchForm.value.client_name;
    let branch_code = this.SearchForm.value.branch_code;
    let nation_id = this.SearchForm.value.nation_id;

    this.FilteredDocuments = this.suspendedDocuments.filter(
      (v) =>
        (client_name == "" ||
          v.client_name.toLowerCase().match(client_name.toLowerCase())) &&
        (branch_code == "" || v.branch_code == branch_code) &&
        (nation_id == "" || v.nation_id?.startsWith(nation_id))
    );
  }

  showErrorMsg(message: string) {
    this.alertService.showAlertError(message, false);
  }

  changePage(newPage: number): void {
    this.page = newPage;
  }

  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }

  dismissModal() {
    this.details = false;
  }

  MoreDetails(document: SuspendedDocuments) {
    this.curDocument = document;
    this.details = !this.details;
  }

  private handleError(error: unknown) {
    const errorMessage =
      error instanceof HttpErrorResponse
        ? JSON.stringify(error.error)
        : error instanceof Error
        ? error.message
        : String(error);

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
